     1→/**
     2→ * Day View Component
     3→ *
     4→ * Displays a 24-hour timeline with hourly slots for a single day
     5→ * Features: current time indicator, timed events in slots, quick event creation
     6→ */
     7→
     8→import React, { useMemo } from 'react';
     9→import type { CalendarEvent } from '../types';
    10→import { format } from 'date-fns';
    11→
    12→interface DayViewProps {
    13→  date: Date;
    14→  events: CalendarEvent[];
    15→  onEventClick?: (event: CalendarEvent, dateKey: string) => void;
    16→  onTimeSlotClick?: (hour: number) => void;
    17→}
    18→
    19→export const DayView: React.FC<DayViewProps> = ({
    20→  date,
    21→  events,
    22→  onEventClick,
    23→  onTimeSlotClick,
    24→}) => {
    25→  const dateKey = format(date, 'yyyy-MM-dd');
    26→  const hours = Array.from({ length: 24 }, (_, i) => i);
    27→
    28→  // Get current hour for time indicator
    29→  const now = new Date();
    30→  const isToday = format(now, 'yyyy-MM-dd') === dateKey;
    31→  const currentHour = now.getHours();
    32→  const currentMinutes = now.getMinutes();
    33→  const currentPosition = isToday ? ((currentHour * 60 + currentMinutes) / (24 * 60)) * 100 : null;
    34→
    35→  // Group events by time
    36→  const timedEvents = useMemo(() => {
    37→    return events.filter(e => !e.isAllDay && e.startTime);
    38→  }, [events]);
    39→
    40→  const allDayEvents = useMemo(() => {
    41→    return events.filter(e => e.isAllDay || !e.startTime);
    42→  }, [events]);
    43→
    44→  // Parse time string "HH:MM" to decimal hours
    45→  const parseTime = (timeStr: string): number => {
    46→    const [hours, minutes] = timeStr.split(':').map(Number);
    47→    return hours + minutes / 60;
    48→  };
    49→
    50→  // Calculate event position and height
    51→  const getEventStyle = (event: CalendarEvent) => {
    52→    if (!event.startTime) return null;
    53→
    54→    const startHour = parseTime(event.startTime);
    55→    const endHour = event.endTime ? parseTime(event.endTime) : startHour + 1;
    56→    const duration = endHour - startHour;
    57→
    58→    return {
    59→      top: `${(startHour / 24) * 100}%`,
    60→      height: `${(duration / 24) * 100}%`,
    61→    };
    62→  };
    63→
    64→  return (
    65→    <div className="h-full flex flex-col">
    66→      {/* Day header */}
    67→      <div className="flex-shrink-0 border-b border-border-light dark:border-border-dark p-4 bg-surface-light dark:bg-surface-dark">
    68→        <div className="flex items-center justify-between">
    69→          <div>
    70→            <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">
